// Check waking hours in Europe/Amsterdam timezone
const now = new Date();
const formatter = new Intl.DateTimeFormat('nl-NL', {
  timeZone: 'Europe/Amsterdam',
  hour: 'numeric',
  hour12: false
});
const amsterdamHour = parseInt(formatter.format(now), 10);

if (amsterdamHour < 7 || amsterdamHour >= 23) {
  // Outside waking hours (07:00-23:00) — skip all checks
  return [];
}

// Get workflows from API response
const response = $input.first().json;
const workflows = response.data || [];

// Exclude this health-check workflow itself (by UUID and name for robustness)
// Assumes ≤10 active workflows per page (homelab). Pagination not implemented.
const SELF_ID   = 'b5717a69-a46c-484e-ac44-aa65e143acfd';
const SELF_NAME = 'n8n Health Check — Idle Workflow Alert';
return workflows
  .filter(w => w.id !== SELF_ID && w.name !== SELF_NAME)
  .map(w => ({ json: { id: w.id, name: w.name } }));

const TWO_HOURS_MS = 2 * 60 * 60 * 1000;
const now = Date.now();
const execItems = $input.all();
const wfItems = $('Time Check + Split').all();
const idle = [];

// Guard: if counts differ, pairing is unsafe — stop chain (visible in n8n execution log)
if (execItems.length !== wfItems.length) {
  return [];
}

for (let i = 0; i < execItems.length; i++) {
  const execResponse = execItems[i].json;
  const wf = wfItems[i].json;

  // Skip if HTTP error
  if (execResponse.error || !execResponse.data) continue;

  const executions = execResponse.data;

  // Per spec: no alert for workflows with no executions yet
  if (executions.length === 0) continue;

  const lastExec = executions[0];
  const lastRunRaw = lastExec.startedAt || lastExec.stoppedAt;
  if (!lastRunRaw) continue;

  const lastRunTime = new Date(lastRunRaw).getTime();
  const idleMs = now - lastRunTime;

  if (idleMs > TWO_HOURS_MS) {
    idle.push({
      name: wf.name || ('Workflow ' + wf.id),
      id: wf.id,
      lastRun: lastExec.startedAt,
      idleMinutes: Math.round(idleMs / 60000)
    });
  }
}

if (idle.length === 0) return [];

return [{ json: { idleWorkflows: idle } }];

const idle = $input.first().json.idleWorkflows;
const lines = idle.map(function(w) {
  const h = Math.floor(w.idleMinutes / 60);
  const m = w.idleMinutes % 60;
  const timeStr = h > 0 ? (h + 'h ' + m + 'm') : (m + 'm');
  let lastRunStr = 'unknown';
  if (w.lastRun) {
    lastRunStr = new Date(w.lastRun).toLocaleTimeString('nl-NL', {
      timeZone: 'Europe/Amsterdam',
      hour: '2-digit',
      minute: '2-digit'
    });
  }
  return '\u2022 ' + w.name + ' \u2014 idle ' + timeStr + ' (last: ' + lastRunStr + ')';
});
const count = idle.length;
const text = '\u26a0\ufe0f n8n health check: ' + count + ' workflow' + (count > 1 ? 's' : '') + ' idle >2h\n\n' + lines.join('\n');
return [{ json: { text: text } }];
